                throw new RuntimeException(cause);
            }
        }
        return results;
    }

    private ProcessingResult processRecord(
        String record,
        CountDownLatch ready,
        CountDownLatch release
    ) throws Exception {
        ready.countDown();
        if (!release.await(5, TimeUnit.SECONDS)) {
